I'm working on a project involving a Car and Engine relationship. I have a Car class that uses composition to manage an Engine class. Additionally, I have a Mechanic class that has an aggregation relationship with both Car and Engine.

car.h
#pragma once
#include "engine.h"
class Car {
    Engine* engine;
    string model;
public:
    Car(string m) : model(m) { engine = new Engine(); }
    ~Car() { delete engine; }
    Engine* getEngine() { return engine; }
};

engine.h
#pragma once
class Car;
class Engine {
    Car* owner;
    int horsepower;
public:
    void setOwner(Car* c) { owner = c; }
    string getOwnerModel() { return owner->getModel(); }
};

mechanic.h
#pragma once
#include "car.h"
#include "engine.h"
class Mechanic {
    Car* currentCar;
    Engine* currentEngine;
public:
    void workOn(Car* c, Engine* e) { currentCar = c; currentEngine = e; }
};

I am getting a compiler error in engine.h: 'use of undefined type 'Car''. If I include car.h in engine.h, I get a circular dependency error because car.h already includes engine.h. How can I allow the Engine class to call a method from the Car class?

